                                if (find(u) !== find(v)) {
                                    union(u, v);
                                }
                            }
                        }

                        // Check if all nodes are connected
                        let tempRoot = find(0);
                        for (let i = 1; i < n; i++) {
                            if (find(i) !== tempRoot) {
                                connected = false;
                                break;
                            }
                        }

                        if (connected) {
                            answer = mid;
                            low = mid + 1;
                            break;
                        } else {
                            // Not connected, need more upgrades
                            low = mid + 1;
                        }
                    }
                }
            }
        }
    }

    return answer;
}
